function VerticalDivider() {
  return (
    <div className="hidden md:flex items-center self-stretch flex-shrink-0">
      <div
        className="w-px h-full"
        style={{
          background:
            "linear-gradient(to bottom, transparent 0%, #CBD5E4 50%, transparent 100%)",
          opacity: 0.7,
          minHeight: "144px",
        }}
      />
    </div>
  );
}

function FeatureRow({ items }: { items: FeatureItem[] }) {
  return (
    <div className="flex flex-col md:flex-row items-stretch w-full">
      {items.map((item, index) => (
        <div key={index} className="flex flex-col md:flex-row items-stretch flex-1 min-w-0">
          {index > 0 && (
            <>
              {/* Mobile horizontal divider */}
              <div className="md:hidden w-full px-4">
                <div className="h-px w-full" style={{ background: "linear-gradient(to right, transparent 0%, #CBD5E4 50%, transparent 100%)", opacity: 0.5 }} />
              </div>
              {/* Desktop vertical divider */}
              <VerticalDivider />
            </>
          )}
          <FeatureCard {...item} />
        </div>
      ))}
    </div>
  );
}

